const row = $input.first()?.json || {};
const lastMod = row.last_mod_end_date ? new Date(row.last_mod_end_date) : null;

const now = new Date();
const MAX_WINDOW_MS = 119 * 24 * 60 * 60 * 1000;

let windowStart = null;
let windowEnd   = null;
let isFirstRun  = false;

if (!lastMod) {
  isFirstRun = true;
} else {
  windowStart = lastMod;
  const maxEnd = new Date(windowStart.getTime() + MAX_WINDOW_MS);
  windowEnd = now > maxEnd ? maxEnd : now;
}

function nvdDate(d) { return d ? d.toISOString().replace('Z', '') : null; }

return [{
  json: {
    isFirstRun,
    windowStart:   nvdDate(windowStart),
    windowEnd:     nvdDate(windowEnd),
    syncStartedAt: now.toISOString()
  }
}];

// Stream NVD pages and upsert one batch at a time. Memory is bounded
// because we never hold more than one page's payload at once.
//
// Uses a direct pg client (allowed via NODE_FUNCTION_ALLOW_EXTERNAL=pg).

const { Client } = require('pg');

const plan   = $input.first().json;
const apiKey = $env.NVD_API_KEY;
if (!apiKey) throw new Error('NVD_API_KEY env var is missing');

const PAGE_SIZE   = 2000;
const INTERVAL_MS = 700;             // under NVD's 50 req / 30s with-key budget
const MAX_RETRIES = 4;

const client = new Client({
  host:     'postgres',
  port:     5432,
  database: $env.POSTGRES_DB,
  user:     $env.POSTGRES_APP_USER,
  password: $env.POSTGRES_APP_PASSWORD,
});
await client.connect();

function nvdDate(d) { return d ? new Date(d).toISOString().replace('Z', '') : null; }
function sleep(ms)  { return new Promise(r => setTimeout(r, ms)); }

function buildUpsert(vulns) {
  const COLS = 13;
  const rows = [];
  const params = [];
  let maxMod = null;
  for (const v of vulns) {
    const c = v?.cve;
    if (!c?.id) continue;
    const descEn = (c.descriptions || []).find(d => d.lang === 'en')?.value || null;
    const m = c.metrics || {};
    const v31 = m.cvssMetricV31?.[0]?.cvssData || null;
    const v30 = m.cvssMetricV30?.[0]?.cvssData || null;
    const v2  = m.cvssMetricV2 ?.[0]?.cvssData || null;
    const cweIds = [];
    for (const w of (c.weaknesses || [])) {
      for (const d of (w.description || [])) {
        if (d.lang === 'en' && typeof d.value === 'string' && d.value.startsWith('CWE-')) {
          cweIds.push(d.value);
        }
      }
    }
    if (!maxMod || (c.lastModified && c.lastModified > maxMod)) maxMod = c.lastModified;
    const b = rows.length * COLS + 1;
    rows.push(`($${b},$${b+1},$${b+2}::timestamptz,$${b+3}::timestamptz,$${b+4},$${b+5},$${b+6},$${b+7},$${b+8},$${b+9},$${b+10},$${b+11}::text[],$${b+12}::jsonb)`);
    params.push(
      c.id, c.sourceIdentifier || null, c.published, c.lastModified, c.vulnStatus || null,
      descEn,
      v31?.baseScore ?? null, v31?.baseSeverity ?? null, v31?.vectorString ?? null,
      v30?.baseScore ?? null, v2?.baseScore ?? null,
      cweIds.length ? cweIds : null,
      JSON.stringify(c),
    );
  }
  if (rows.length === 0) return { sql: null, params: [], count: 0, maxMod: null };
  const sql =
    'INSERT INTO cves (cve_id, source_identifier, published, last_modified, vuln_status, description_en, ' +
    'cvss_v31_score, cvss_v31_severity, cvss_v31_vector, cvss_v30_score, cvss_v2_score, cwe_ids, raw) ' +
    'VALUES ' + rows.join(',') + ' ' +
    'ON CONFLICT (cve_id) DO UPDATE SET ' +
    'source_identifier = EXCLUDED.source_identifier, published = EXCLUDED.published, ' +
    'last_modified = EXCLUDED.last_modified, vuln_status = EXCLUDED.vuln_status, ' +
    'description_en = EXCLUDED.description_en, cvss_v31_score = EXCLUDED.cvss_v31_score, ' +
    'cvss_v31_severity = EXCLUDED.cvss_v31_severity, cvss_v31_vector = EXCLUDED.cvss_v31_vector, ' +
    'cvss_v30_score = EXCLUDED.cvss_v30_score, cvss_v2_score = EXCLUDED.cvss_v2_score, ' +
    'cwe_ids = EXCLUDED.cwe_ids, raw = EXCLUDED.raw ' +
    'WHERE cves.last_modified IS NULL OR cves.last_modified < EXCLUDED.last_modified';
  return { sql, params, count: rows.length, maxMod };
}

let startIndex   = 0;
let totalResults = null;
let pages        = 0;
let upserted     = 0;
let maxModified  = null;
const startMs    = Date.now();

try {
  while (true) {
    const qsParts = [
      'resultsPerPage=' + PAGE_SIZE,
      'startIndex=' + startIndex,
    ];
    if (plan.windowStart) qsParts.push('lastModStartDate=' + encodeURIComponent(plan.windowStart));
    if (plan.windowEnd)   qsParts.push('lastModEndDate='   + encodeURIComponent(plan.windowEnd));
    const url = 'https://services.nvd.nist.gov/rest/json/cves/2.0?' + qsParts.join('&');

    let resp = null;
    let lastErr = null;
    for (let attempt = 0; attempt < MAX_RETRIES; attempt++) {
      try {
        resp = await this.helpers.httpRequest({
          method: 'GET',
          url,
          headers: { apiKey, 'User-Agent': 'n8n-nvd-sync/1.0' },
          json: true,
          timeout: 60000,
        });
        break;
      } catch (e) {
        lastErr = e;
        await sleep(1500 * (attempt + 1));
      }
    }
    if (!resp) throw new Error('NVD fetch failed after retries: ' + (lastErr?.message || 'unknown'));

    totalResults = resp.totalResults ?? 0;
    const vulns  = resp.vulnerabilities || [];
    if (vulns.length === 0) break;

    const batch = buildUpsert(vulns);
    if (batch.sql) {
      await client.query(batch.sql, batch.params);
      upserted += batch.count;
      if (batch.maxMod && (!maxModified || batch.maxMod > maxModified)) maxModified = batch.maxMod;
    }
    pages++;

    await client.query(
      'UPDATE sync_runs SET pages_fetched=$1, cves_upserted=$2, total_results=$3 WHERE id=$4',
      [pages, upserted, totalResults, plan.runId],
    );

    if (startIndex + PAGE_SIZE >= totalResults) break;
    startIndex += PAGE_SIZE;
    await sleep(INTERVAL_MS);
  }
} finally {
  await client.end();
}

return [{
  json: {
    runId:        plan.runId,
    pagesFetched: pages,
    cvesUpserted: upserted,
    totalResults,
    newHighWater: maxModified || plan.windowEnd || plan.syncStartedAt,
    durationMs:   Date.now() - startMs,
  }
}];
